const chatInput = ($input.first().json.chatInput || $input.first().json.input || '').trim();
console.log('Input:', chatInput);
const isSummary = /\b(summary|report|total|spending|how much|breakdown|stats)\b/i.test(chatInput);
const isHelp = /^(\?|help|\/help)$/i.test(chatInput);
return [{ json: {
  chat_input: chatInput,
  intent: isSummary ? 'summary' : isHelp ? 'help' : 'expense'
}}];

// This node ALWAYS outputs data regardless of how many rows the sheet has
