const allRows = $input.all();
const chatInput = $('Detect Intent').first().json.chat_input;

// Calculate current month total from existing rows (0 if empty)
const now = new Date();
const currentMonth = now.toLocaleString('en-US', {month:'long'}) + ' ' + now.getFullYear();

const monthTotal = allRows
  .filter(r => (r.json['Month'] || '') === currentMonth)
  .reduce((sum, r) => sum + parseFloat(r.json['Amount'] || 0), 0);

console.log('Rows in sheet:', allRows.length, '| Month total so far:', monthTotal);

