const rawText = ($json.text || $json.output || '').trim();
const prepared = $('Prepare Data').first().json;
const chatInput = prepared.chat_input;
console.log('AI response:', rawText);

let parsed = null;
try { parsed = JSON.parse(rawText); } catch(e) {}
if (!parsed) {
  try { const m = rawText.match(/\{[\s\S]*\}/); if(m) parsed = JSON.parse(m[0]); } catch(e) {}
}

if (!parsed || !parsed.is_expense || !parsed.amount || parseFloat(parsed.amount) <= 0) {
  return [{ json: {
    valid: false,
    reply: `I couldn't identify an expense amount in that message.\n\nPlease include an amount, like:\n• "spent 500 on lunch"\n• "uber 150"\n• "1200 electricity bill"`
  }}];
}

const emo = {'Food & Dining':'🍕','Transport':'🚗','Shopping':'🛍️','Bills & Utilities':'💡','Entertainment':'🎬','Health':'🏥','Business':'💼','Education':'📚','Other':'💰'};
const cat      = parsed.category || 'Other';
const amount   = parseFloat(parsed.amount);
const currency = parsed.currency || 'INR';
const symbol   = currency === 'INR' ? '₹' : currency + ' ';
const dateStr  = parsed.date || new Date().toISOString().split('T')[0];

// Derive month from parsed date (not today)
const parsedDate     = new Date(dateStr);
const entryMonth     = parsedDate.toLocaleString('en-US', {month:'long'}) + ' ' + parsedDate.getFullYear();

// Running total for that specific month
const allRows        = $('Read All Expenses').all();
const entryMonthTotal = allRows
  .filter(r => (r.json['Month'] || '') === entryMonth)
  .reduce((sum, r) => sum + parseFloat(r.json['Amount'] || 0), 0);
const newTotal = entryMonthTotal + amount;

console.log(`Saving: ${symbol}${amount} | ${cat} | ${parsed.description} | Month: ${entryMonth} | Total: ${newTotal}`);

return [{ json: {
  valid:         true,
  Date:          dateStr,
  Amount:        amount,
  Category:      cat,
  Description:   parsed.description || chatInput,
  Currency:      currency,
  Month:         entryMonth,
  "Raw Message": chatInput,
  Total:         newTotal,
  _display: `${emo[cat]||'💰'} *${cat}* — ${parsed.description || chatInput}\n💳 ${symbol}${amount}\n📅 ${dateStr}\n📊 ${entryMonth} total: ${symbol}${newTotal.toFixed(0)}`
}}];

const rows = $input.all();
const now = new Date();
const chatInput = $('Detect Intent').first().json.chat_input;

// Detect if user asked for specific month
const monthNames = ['january','february','march','april','may','june','july','august','september','october','november','december'];
let targetMonth = null;

const lower = chatInput.toLowerCase();
for (const m of monthNames) {
  if (lower.includes(m)) {
    const yearMatch = lower.match(/20(\d{2})/);
    const shortYearMatch = lower.match(/\b(\d{2})\b/);
    let year = now.getFullYear();
    if (yearMatch) year = parseInt(yearMatch[0]);
    else if (shortYearMatch) year = 2000 + parseInt(shortYearMatch[1]);
    targetMonth = m.charAt(0).toUpperCase() + m.slice(1) + ' ' + year;
    break;
  }
}

if (!targetMonth) {
  targetMonth = now.toLocaleString('en-US', {month:'long'}) + ' ' + now.getFullYear();
}

console.log('Summary for month:', targetMonth);

const thisMonth = rows.filter(r => (r.json['Month'] || '') === targetMonth);

if (rows.length === 0 || thisMonth.length === 0) {
  return [{ json: { output: `📊 No expenses found for *${targetMonth}*.\n\nTry: SUMMARY or "summary march"` }}];
}

const total = thisMonth.reduce((s,r) => s + parseFloat(r.json['Amount']||0), 0);
const byCategory = {};
for (const r of thisMonth) {
  const cat = r.json['Category'] || 'Other';
  byCategory[cat] = (byCategory[cat]||0) + parseFloat(r.json['Amount']||0);
}
const sorted = Object.entries(byCategory).sort((a,b) => b[1]-a[1]);
const emo = {'Food & Dining':'🍕','Transport':'🚗','Shopping':'🛍️','Bills & Utilities':'💡','Entertainment':'🎬','Health':'🏥','Business':'💼','Education':'📚','Other':'💰'};
const lines = sorted.map(([c,a]) => `${emo[c]||'💰'} ${c}: ₹${a.toFixed(0)} (${((a/total)*100).toFixed(0)}%)`).join('\n');

return [{ json: { output:
  `📊 *${targetMonth} Report*\n\n` +
  `💳 *Total: ₹${total.toFixed(0)}*\n` +
  `📝 Entries: ${thisMonth.length}\n` +
  `📈 Daily avg: ₹${(total/now.getDate()).toFixed(0)}\n` +
  `🔝 Top: ${emo[sorted[0]?.[0]]||'💰'} ${sorted[0]?.[0]}\n\n` +
  `*Breakdown:*\n${lines}`
}}];
